import scala.util.Bisect

def solve(nums: Array[Long], k: Long): Long = {
  val sorted = nums.sorted
  var maxLen = 0L
  for (i <- 0 until sorted.length) {
    val target = k * sorted(i)
    val j = Bisect.bisectRight(sorted, target) - 1
    if (j >= i) {
      val currentLen = j - i + 1
      if (currentLen > maxLen) maxLen = currentLen
    }
  }
  nums.length - maxLen
}
