def solve(nums: Array[Long], k: Long): Long = {
  val sorted = nums.sorted
  val n = sorted.length
  var maxLen = 1L
  for (i <- 0 until n) {
    val target = k * sorted(i)
    var low = i
    var high = n - 1
    var best = i
    while (low <= high) {
      val mid = (low + high) / 2
      if (sorted(mid) <= target) {
        best = mid
        low = mid + 1
      } else {
        high = mid - 1
      }
    }
    val currentLen = best - i + 1
    if (currentLen > maxLen) {
      maxLen = currentLen
    }
  }
  n - maxLen
}
